109→  if (el.dataset?.quoteId) return `[quote:${el.dataset.quoteId}]`.length
110→  if (el.tagName === 'BR') return 1
111→  let n = 0
112→  for (const child of el.childNodes) n += nodeLen(child)
113→  return n
114→}
